class Solution:
    def findRadius(self, houses: List[int], heaters: List[int]) -> int:
        houses.sort(); heaters.sort()
        ans = 0
        for h in houses:
            i = bisect.bisect_left(heaters, h)
            d = float("inf")
            if i < len(heaters): d = min(d, abs(heaters[i]-h))
            if i: d = min(d, abs(heaters[i-1]-h))
            ans = max(ans, d)
        return ans

